import json
import pandas as pd

# --- Field mappings ---
FIELD_MAP = {
    "user_id": ["id", "user_id", "userId"],
    "email": ["email", "email_address"],
    "name": ["full_name", "name", "userName"],
    "created_date": ["registration_date", "created_at", "joined"],
    "status": ["status", "is_active", "active"],
}

def normalize_row(row, source_label):
    """Map a source row to unified schema."""
    normalized = {}
    for unified_field, possible_names in FIELD_MAP.items():
        for name in possible_names:
            if name in row and pd.notna(row[name]):
                val = row[name]
                # Normalize status field
                if unified_field == "status":
                    if isinstance(val, bool):
                        val = "active" if val else "inactive"
                    elif isinstance(val, str):
                        val = val.lower()
                normalized[unified_field] = val
                break
    return normalized

def main():
    # --- Read sources ---
    # Source A: JSON
    with open("/data/source_a/users.json", "r") as f:
        source_a_list = json.load(f)
    source_a = pd.DataFrame(source_a_list)

    # Source B: CSV
    source_b = pd.read_csv("/data/source_b/users.csv")

    # Source C: Parquet
    source_c = pd.read_parquet("/data/source_c/users.parquet")

    # --- Normalize all sources to unified schema ---
    records = {}  # user_id -> {source_label: normalized_row}

    for src_name, df in [("source_a", source_a), ("source_b", source_b), ("source_c", source_c)]:
        for _, row in df.iterrows():
            uid = int(row["id"]) if "id" in row else \
                  int(row["user_id"]) if "user_id" in row else \
                  int(row["userId"])
            norm = normalize_row(row, src_name)
            norm["user_id"] = uid
            if uid not in records:
                records[uid] = {}
            records[uid][src_name] = norm

    # --- Merge with priority and detect conflicts ---
    merged_rows = []
    conflicts = []

    for uid in sorted(records.keys()):
        sources = records[uid]
        merged = {}

        # Collect all values per field across sources
        all_fields = set()
        for src_data in sources.values():
            all_fields.update(src_data.keys())

        for field in all_fields:
            if field == "user_id":
                continue
            values_by_source = {}
            for src_label in ["source_a", "source_b", "source_c"]:
                if src_label in sources and field in sources[src_label]:
                    val = sources[src_label][field]
                    # Normalize date format
                    if field == "created_date":
                        try:
                            from datetime import datetime
                            dt = datetime.strptime(str(val), "%Y-%m-%d")
                            val = dt.strftime("%Y-%m-%d")
                        except ValueError:
                            pass
                    values_by_source[src_label] = val

            # Determine selected value (highest priority)
            selected = None
            for src_label in ["source_a", "source_b", "source_c"]:
                if src_label in values_by_source:
                    selected = values_by_source[src_label]
                    break

            merged[field] = selected

            # Check for conflicts (same field, different non-null values across sources)
            present_values = {k: v for k, v in values_by_source.items() if v is not None}
            unique_vals = set(str(v) for v in present_values.values())
            if len(unique_vals) > 1:
                conflict_entry = {
                    "user_id": uid,
                    "field": field,
                    "values": {},
                    "selected": selected,
                }
                for src_label in ["source_a", "source_b", "source_c"]:
                    if src_label in present_values:
                        conflict_entry["values"][src_label] = present_values[src_label]
                conflicts.append(conflict_entry)

        merged_rows.append(merged)

    # --- Build output DataFrame ---
    out_df = pd.DataFrame(merged_rows)
    out_df["user_id"] = out_df["user_id"].astype(int)

    # Ensure column order
